
.mvu-root {
  width: 100%;
  max-width: 720px;
  margin: 16px auto;
  font-family: 'Microsoft YaHei', sans-serif;
  border-radius: 16px;
  overflow: hidden;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.3);
}

.mvu-header {
  background: linear-gradient(135deg, #2a0835 0%, #1a1a1a 100%);
  padding: 14px 20px;
  color: #FF69B4;
  font-size: 18px;
  font-weight: bold;
  text-align: center;
  letter-spacing: 2px;
}

.mvu-body {
  background: rgba(20, 6, 28, 0.97);
  padding: 14px;
}

.char-card {
  background: rgba(255, 105, 180, 0.05);
  border: 1px solid rgba(255, 105, 180, 0.18);
  border-radius: 12px;
  padding: 14px;
  margin-bottom: 10px;
}

.char-card.empty-hint {
  text-align: center;
  opacity: 0.5;
  .detail-row { color: #888; }
}

.char-title {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 10px;
}

.char-icon {
  font-size: 18px;
}

.char-name {
  color: #FF69B4;
  font-size: 16px;
  font-weight: bold;
}

.char-age {
  color: #9078a0;
  font-size: 12px;
}

.badge {
  font-size: 10px;
  padding: 2px 8px;
  border-radius: 10px;
  margin-left: auto;
}

.badge-on {
  background: rgba(0, 255, 100, 0.15);
  color: #00ff64;
}

.char-bars {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 10px;
}

.bar-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.bar-label {
  color: #b8a0c0;
  font-size: 12px;
  min-width: 44px;
  text-align: right;
}

.bar-track {
  flex: 1;
  height: 8px;
  background: rgba(255, 255, 255, 0.08);
  border-radius: 4px;
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 0.5s ease;
}

.bar-fill.affection {
  background: linear-gradient(90deg, #FF69B4, #ff1493);
}

.bar-fill.arousal {
  background: linear-gradient(90deg, #ff6347, #ff1493);
}

.bar-val {
  color: #d8c0e0;
  font-size: 12px;
  min-width: 56px;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.phase-tag {
  font-size: 10px;
  padding: 1px 6px;
  border-radius: 6px;
  background: rgba(255, 105, 180, 0.15);
  color: #FF69B4;
}

.char-detail {
  border-top: 1px solid rgba(255, 105, 180, 0.12);
  padding-top: 8px;
}

.detail-row {
  color: #c0a8d0;
  font-size: 12px;
  line-height: 1.7;
}

.detail-row b {
  color: #FF69B4;
  margin-right: 4px;
}

.sys-card {
  background: linear-gradient(135deg, #101820 0%, #1a2440 100%);
  border: 1px solid rgba(120, 180, 255, 0.25);
  border-radius: 12px;
  padding: 14px;
}

.sys-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}

.sys-icon {
  font-size: 18px;
}

.sys-title {
  color: #9fd3ff;
  font-size: 16px;
  font-weight: bold;
}

.sys-points {
  color: #c0d8f0;
  font-size: 14px;
  margin-bottom: 8px;
}

.points-val {
  color: #7CFFB2;
  font-size: 20px;
  font-weight: bold;
  margin-left: 6px;
}

.sys-summary {
  color: #d0dff0;
  font-size: 13px;
  line-height: 1.6;
  padding: 10px;
  background: rgba(255, 255, 255, 0.03);
  border-radius: 8px;
  margin-bottom: 10px;
}

.sys-suggestions {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 8px;
}

.sugg-card {
  background: rgba(159, 211, 255, 0.06);
  border-radius: 8px;
  padding: 10px;
}

.sugg-label {
  color: #9fd3ff;
  font-size: 12px;
  font-weight: bold;
  margin-bottom: 4px;
}

.sugg-text {
  color: #b8cce0;
  font-size: 12px;
  line-height: 1.5;
}

@media (max-width: 600px) {
  .sys-suggestions {
    grid-template-columns: 1fr;
  }
}
